import "fmt"

// Tier represents the analysis capability tier for a language.
type Tier int

const (
	// TierNone indicates no analysis capability.
	TierNone Tier = iota
	// TierGeneric indicates generic (file-level) analysis only.
	TierGeneric
	// TierLint indicates lint-level analysis.
	TierLint
	// TierParse indicates parse-tree-level analysis.
	TierParse
	// TierFull indicates full semantic analysis.
	TierFull
)

var tierStrings = map[Tier]string{
	TierNone:    "None",
	TierGeneric: "Generic",
	TierLint:    "Lint",
	TierParse:   "Parse",
	TierFull:    "Full",
}

// String returns a human-readable name for the tier.
func (t Tier) String() string {
	if s, ok := tierStrings[t]; ok {
		return s
	}
	return fmt.Sprintf("Tier(%d)", int(t))
}

// languageTiers maps every known language ID to its analysis capability tier.
var languageTiers = map[string]Tier{
	"go":     TierFull,
	"ts":     TierFull,
	"js":     TierFull,
	"py":     TierFull,
	"rs":     TierFull,
	"rb":     TierGeneric,
	"java":   TierGeneric,
	"kt":     TierGeneric,
	"sh":     TierGeneric,
	"c":      TierGeneric,
	"cpp":    TierGeneric,
	"cs":     TierGeneric,
	"swift":  TierGeneric,
	"php":    TierGeneric,
	"elixir": TierGeneric,
	"erlang": TierGeneric,
	"scala":  TierGeneric,
	"lua":    TierGeneric,
	"r":      TierGeneric,
	"zig":    TierGeneric,
	"sql":    TierGeneric,
	"proto":  TierGeneric,
}

// TierForLanguage returns the analysis tier for the given language ID.
// If the language is not in the registry, TierGeneric is returned.
func TierForLanguage(lang string) Tier {
	if t, ok := languageTiers[lang]; ok {
		return t
	}
	return TierGeneric
}

