import "testing"

func TestTierForLanguageKnownLanguages(t *testing.T) {
	want := map[string]Tier{
		"go":     TierFull,
		"ts":     TierFull,
		"js":     TierFull,
		"py":     TierFull,
		"rs":     TierFull,
		"rb":     TierGeneric,
		"java":   TierGeneric,
		"kt":     TierGeneric,
		"sh":     TierGeneric,
		"c":      TierGeneric,
		"cpp":    TierGeneric,
		"cs":     TierGeneric,
		"swift":  TierGeneric,
		"php":    TierGeneric,
		"elixir": TierGeneric,
		"erlang": TierGeneric,
		"scala":  TierGeneric,
		"lua":    TierGeneric,
		"r":      TierGeneric,
		"zig":    TierGeneric,
		"sql":    TierGeneric,
		"proto":  TierGeneric,
	}

	for lang, expectedTier := range want {
		got := TierForLanguage(lang)
		if got != expectedTier {
			t.Errorf("TierForLanguage(%q) = %s, want %s", lang, got, expectedTier)
		}
	}
}

func TestTierForLanguageUnknownReturnsGeneric(t *testing.T) {
	if got := TierForLanguage("unknownlang"); got != TierGeneric {
		t.Errorf("TierForLanguage(\"unknownlang\") = %s, want %s", got, TierGeneric)
	}
}

func TestTierString(t *testing.T) {
	tests := []struct {
		tier Tier
		want string
	}{
		{TierNone, "None"},
		{TierGeneric, "Generic"},
		{TierLint, "Lint"},
		{TierParse, "Parse"},
		{TierFull, "Full"},
		{Tier(99), "Tier(99)"},
	}

	for _, tt := range tests {
		got := tt.tier.String()
		if got != tt.want {
			t.Errorf("(%s).String() = %q, want %q", tierStrings[tt.tier], got, tt.want)
		}
	}
}

func TestLanguageTiersCompleteness(t *testing.T) {
	// Every entry in the registry must map to a non-zero (non-TierNone) tier.
	for lang, tier := range languageTiers {
		if tier == TierNone {
			t.Errorf("languageTiers[%q] = TierNone; every known language must have a non-None tier", lang)
		}
	}
	// The registry must contain exactly the expected 22 entries.
	if len(languageTiers) != 22 {
		t.Errorf("languageTiers has %d entries, want 22 — a new language may have been added to discovery without a tier entry", len(languageTiers))
	}
}

